import{_ as a,o,c as i,ag as r}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Fundamentos de PID","description":"","frontmatter":{},"headers":[],"relativePath":"es/control-systems/basics/pid-basics.md","filePath":"es/control-systems/basics/pid-basics.md"}'),n={name:"es/control-systems/basics/pid-basics.md"};function l(s,e,t,c,d,p){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="fundamentos-de-pid" tabindex="-1">Fundamentos de PID <a class="header-anchor" href="#fundamentos-de-pid" aria-label="Permalink to &quot;Fundamentos de PID&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>El control PID es un método ampliamente utilizado en sistemas de control en lazo cerrado. Ajusta la salida de control en función de la diferencia entre un valor deseado y el valor medido.</p><p>PID significa Proporcional, Integral y Derivativo. Estos tres términos definen cómo el controlador responde al error.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito del control PID es mantener una variable de proceso en un valor deseado (setpoint) con estabilidad y precisión.</p><p>Se utiliza para:</p><ul><li>Reducir el error en estado estacionario</li><li>Mejorar la velocidad de respuesta</li><li>Minimizar oscilaciones</li><li>Compensar perturbaciones</li></ul><p>El control PID proporciona un balance entre rapidez de respuesta y estabilidad.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Un controlador PID calcula una salida basada en el error entre el setpoint y el valor medido.</p><h3 id="proporcional-p" tabindex="-1">Proporcional (P) <a class="header-anchor" href="#proporcional-p" aria-label="Permalink to &quot;Proporcional (P)&quot;">​</a></h3><p>El término proporcional responde al error actual.</p><ul><li>Un error grande produce una corrección grande</li><li>Un error pequeño produce una corrección pequeña</li></ul><p>Proporciona una respuesta inmediata, pero por sí solo no elimina el error en estado estacionario.</p><h3 id="integral-i" tabindex="-1">Integral (I) <a class="header-anchor" href="#integral-i" aria-label="Permalink to &quot;Integral (I)&quot;">​</a></h3><p>El término integral responde a la acumulación del error en el tiempo.</p><ul><li>Incrementa la salida si el error persiste</li><li>Elimina el error en estado estacionario</li></ul><p>Un exceso de acción integral puede provocar respuestas lentas u oscilaciones.</p><h3 id="derivativo-d" tabindex="-1">Derivativo (D) <a class="header-anchor" href="#derivativo-d" aria-label="Permalink to &quot;Derivativo (D)&quot;">​</a></h3><p>El término derivativo responde a la velocidad de cambio del error.</p><ul><li>Predice el comportamiento futuro</li><li>Reduce el sobreimpulso (overshoot)</li><li>Mejora la estabilidad</li></ul><p>Es sensible al ruido y debe utilizarse con cuidado.</p><h3 id="accion-combinada" tabindex="-1">Acción combinada <a class="header-anchor" href="#accion-combinada" aria-label="Permalink to &quot;Acción combinada&quot;">​</a></h3><p>La salida del controlador es la combinación de los tres términos.</p><ul><li>P actúa sobre el error presente</li><li>I corrige el error acumulado</li><li>D anticipa el error futuro</li></ul><p>El balance entre estos términos determina el comportamiento del sistema.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>El control PID se utiliza en la mayoría de los lazos de control industrial, incluyendo:</p><ul><li>Control de temperatura</li><li>Regulación de flujo y presión</li><li>Control de velocidad de motores</li><li>Control de nivel en tanques</li><li>Sistemas de control de posición</li></ul><p>Es el enfoque estándar para el control continuo de procesos.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><p>El ajuste (tuning) es crítico. Las ganancias de P, I y D deben adaptarse a cada proceso.</p><p>Un exceso de ganancia proporcional puede causar oscilaciones.</p><p>Demasiada acción integral puede generar inestabilidad o recuperación lenta.</p><p>La acción derivativa mejora la estabilidad, pero puede amplificar el ruido.</p><p>La dinámica del proceso afecta el ajuste. Sistemas rápidos y lentos requieren configuraciones distintas.</p><p>La precisión y el tiempo de respuesta de los sensores impactan directamente el desempeño.</p><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><p>Un error común es usar PID sin comprender el comportamiento del proceso, lo que conduce a un mal ajuste y control inestable.</p><p>No todos los sistemas requieren los tres términos. Muchas aplicaciones utilizan solo control PI.</p><p>Comienza con un ajuste simple y aumenta la complejidad solo si es necesario.</p><p>Verifica el desempeño en condiciones reales de operación, no solo en pruebas iniciales.</p><p>Puede ser necesario aplicar filtrado de señal cuando se utiliza acción derivativa.</p>',44)])])}const h=a(n,[["render",l]]);export{m as __pageData,h as default};
